1	type Item = { type: string };
2	type Input = { steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	
6	const PREMIUM_BY_TYPE: Record<string, number> = {
7	  amulet: 71,
8	  staff: 93,
9	  potion: 49,
10	  sword: 115,
11	};
12	
13	export function runScenario(input: unknown): unknown {
14	  const { steps } = input as Input;
15	  const premium = computePremium(steps[0].items);
16	  return { results: [{ premium }] };
17	}
18	
19	function computePremium(items: Item[]): number {
20	  if (items.length === 0) return PROCESSING_FEE;
21	  return PREMIUM_BY_TYPE[items[0].type];
22	}
